    storiaMeridiano: "Elemento: Terra · Organo: Stomaco · Polarità: Yang. Riceve e trasforma gli alimenti; radica e dà sostegno. Muscolo indicatore: Gran Pettorale Clavicolare.",
    fiore: [ { nome: "Billy Goat Plum", tipo: "Fiore del Deserto", squilibri: ["Incapacità di godere del sesso", "Ribrezzo per il mio fisico", "Repulsione sessuale"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno a godere della mia sessualità, a provare piacere sessuale, ad accettare la mia mascolinità/femminilità e provare piacere nel vivere nel mio corpo." }, { nome: "Chaparral", tipo: "Fiore del Deserto", squilibri: ["Intensa desolazione interiore QO Tristezza", "Sentirmi sempre solo e \"tagliato fuori\" QO Ansiosa amarezza", "Interiorizzare le cose creando tensione nervosa", "Chiusura nel mio mondo magico"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno ad accettare l'amicizia degli altri per tutta la vita, pormi in connessione con la mia fonte interiore ed esprimere le mie emozioni e la mia energia creativa." }, { nome: "Waratah", tipo: "Fiore Australiano", squilibri: ["Disperazione nera", "Mancanza di speranza", "Q) Incapacità di reagire ad una crisi"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno ad acquisire il coraggio di connettermi alla vita con tenacia, adattabilita e fiducia." }, { nome: "Holly", tipo: "Fiore di Bach", squilibri: ["Malizia", "Animosita", "Bramare ie caratteristiche o la buona sorte di altri", "OQ) Aspettarsi il peggio dagli altri"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno a far si che i miei pensieri e sentimenti si basino sul potere più alto dell'amore." }, { nome: "Cane Cholla Cactus", tipo: "Fiore del Deserto", squilibri: ["Incapacità a comprendere o trovare la soluzione a un problema", "Mantenere troppo rigido un atteggiamento o l'aspettativa riguardo a una situ", "azione", "Mancanza di atteggiamento difensivo o di pretesa nelle mie relazioni con gli altri"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno ad ascoltare gli altri con comprensione e mentalita aperta e a prendere decisioni con fiducia." }, { nome: "Walnut", tipo: "Fiore di Bach", squilibri: ["Essere influenzato da forti ed energiche cause esterne", "Apertura ai pensieri ed emozioni non in linea con il portare a termine i miei", "obiettivi", "Incapacità di avanzare nella mia vita"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno ad ascoltare la mia voce interiore e con fiducia seguire la mia propria ed unica direzione nella vita." } ],
