    storiaMeridiano: "Elemento: Fuoco · Organo: Intestino Tenue · Polarità: Yang. Separa il puro dall'impuro, sul piano fisico e mentale (discernimento). Muscolo indicatore: Quadricipite.",
    fiore: [ { nome: "Oak", tipo: "Fiore di Bach", squilibri: ["Lottare contro la mia vita e i suoi processi di crescita", "Scoraggiamento nei confronti dei problemi"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno ad affrontare la vita con fiducia, forza, coraggio e stabilità." }, { nome: "Old Man Banksia", tipo: "Fiore Australiano", squilibri: ["Indolenza", "Stanchezza", "Poca energia", "Frustrazione", "Sconforto", "Eccesso"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno a mostrare tanta gentilezza e considerazione per me stesso quanto per gli altri e vivere la vita con energia, entusiasmo ed interesse." }, { nome: "Hoptree", tipo: "Fiore del Deserto", squilibri: ["i Incapacita' a restare concentrato su ciò che e importante", "Cj Tentare con troppa forza di controllare O Incapacità di evitare le distrazioni", "Perdere di vista il mio vero scopo QO Profonda ansia interiore"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno a entrare in contatto con un profondo livello di obiettivi, rimanere focalizzato su ciò che é più essenziale e rinunciare con gioia al mio desiderio personale per uno piti alto." }, { nome: "Mustard", tipo: "Fiore di Bach", squilibri: ["Eccessiva concentrazione sugli squallori della vita", "Instabilita", "Incapacità di capire da dove nascono le mie emozioni"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno a portare amore ad ogni esperienza, mantenere equilibrio nella mia vita e progredire con fiducia poiché ogni esperienza contiene delle opportunita per crescere." }, { nome: "Rock Rose", tipo: "Fiore di Bach", squilibri: ["Estrema paura causata da incidenti, malattie 0 esperienze sconosciute"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno a sviluppare il coraggio e la capacità di dimenticare i miei problemi. Mi concentrero sull'aiutare le altre persone in situazioni d'emergenza." }, { nome: "Mountain Devil", tipo: "Fiore Australiano", squilibri: ["Ot Odio", "Rabbia", "Sospetto", "Tenere rancore"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno a riconoscere ed accettare le mie emozioni. Inoltre accetterd, perdonerd e amero me stesso e gli altri." } ],
