    storiaMeridiano: "Elemento: Fuoco Etere · Organo: Tiroide · Polarità: Yang. Triplice Riscaldatore (aspetto Tiroide): coordina i tre focolai e la termoregolazione; metabolismo. Muscolo indicatore: Piccolo Rotondo.",
    fiore: [ { nome: "Cerato", tipo: "Fiore di Bach", squilibri: ["Cercare conferme attrayerso gli occhi degli altri", "Agire seguendo ciò che gli altri yorrebbero che io facessi anziché il mio giudizio"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno ad apprezzarmi basandomi sulla mia direzione interiore e sul mio giudizio." }, { nome: "Kangaroo Paw", tipo: "Fiore Australiano", squilibri: ["Inconsapevolezza", "Goffaggine", "Inettitudine", "Insensibilita", "QO) Mancanza di tatto"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno a gioire della gente in modo affabile, sensibile e rilassato." }, { nome: "Sundew", tipo: "Fiore Australiano", squilibri: ["Essere vago", "Incoerenza", "Indecisione", "Mancanza di concentrazione", "Sognare ad occhi aperti", "Separare le situazioni emotive"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno ad ancorarmi alla certezza dell'amore e rimanere focalizzato ed attento ai dettagli." }, { nome: "Flame Tree", tipo: "Fiore Australiano", squilibri: ["Paura delle responsabilità", "Opprimente paura di essere rifiutato"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno ad agire con sicurezza, fiducia in me stesso, forza ed impegno." }, { nome: "Southern Cross", tipo: "Fiore Australiano", squilibri: ["Mentalità vittimista", "Amarezza", "Mancanza di coscienza", "Lamentarmi", "Martirizzarmi"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno a volere forza personale e responsabilità. Continuerò a lavorare per creare circostanze positive e un'atmosfera di ottimismo nella mia vita." }, { nome: "Gorse", tipo: "Fiore di Bach", squilibri: ["Abbattermi e scoraggiarmi"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno ad usare il potere curativo dell'amore per creare un nuovo sentimento di speranza e fiducia nella mia vita." }, { nome: "Red Chestnut", tipo: "Fiore di Bach", squilibri: ["Apprensione riguardo il benessere degli altri e le proiezioni delle mie emozioni su", "di loro stessi"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno a restare in sintonia con gli altri con amore." } ],
