    fiore: [ { nome: "Rock Water", tipo: "Fiore di Bach", squilibri: ["Innaturale rinuncia di me stesso", "Limitazioni", "Sacrificarmi", "Inflessibilita mentale"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno ad essere pit: buono con me Stesso e seguire la disciplina che ho in me e nella vita." }, { nome: "Wild Potato", tipo: "Fiore Australiano", squilibri: ["OFrustrazione", "Ingombro fisico", "Essere in soyrappeso"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno ad avere caro il mio corpo e progredire nella vita con libertà e vitalita." }, { nome: "Wisteria", tipo: "Fiore Australiano", squilibri: ["Frigidita", "Immagine da \"Macho\"", "Isterismo sessuale"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno ad incoraggiare Vintimita nelle mie relazioni e a provare calore e sicurezza nella mia sessualità." }, { nome: "Spineless Prickly Pear", tipo: "Fiore del Deserto", squilibri: ["Mancanza di scopi e di forza", "Dipendenza da fonti esterne per avere un senso di identità"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno a riconoscere che ogni cosa esiste in un dato momento per fornire uno strumento per l'esistenza. Io mi basto." }, { nome: "Wolfberry", tipo: "Fiore del Deserto", squilibri: ["Profonda tristezza proveniente dal passato", "Trattenere o evitare il dolore", "Senso di profondo cambiamento interiore che non riesco a capire"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno a permettere al mio dolore e alla mia tristezza di portarmi ad un nuovo livello di coscienza e di permettere che avvengano profondi processi interiori senza aver bisogno di capirli." }, { nome: "Aspen", tipo: "Fiore di Bach", squilibri: ["Paura, panico o brutti presentimenti da una fonte che non può essere identificata o misurata con i sensi"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno ad avere il coraggio e sufficiente fiducia per procedere nella vita in tutte le circostanze." }, { nome: "Wild Oat", tipo: "Fiore di Bach", squilibri: ["Incapacità di realizzare gli scopi della mia vita, 0 di adeguarli al mio modo di", "vivere", "Mancanza di concentrazione", "Scoraggiamento"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno ad integrare le mie energie in modo da intuire e poi realizzare gli intenti della mia vita." } ],
