    storiaMeridiano: "Elemento: Metallo · Organo: Polmone · Polarità: Yin. Governa il Qi e il respiro; confine e protezione. Muscolo indicatore: Deltoide Medio.",
    fiore: [ { nome: "White Desert Primrose", tipo: "Fiore del Deserto", squilibri: ["Atteggiamento di confusione e di dubbio verso me stesso", "Difficoltà a discernere chiaramente come azioni o espressioni siano in armonia con", "la mia natura interiore", "Lasciarmi influenzare da ideali che io o altri hanno create ma che non", "necessariamente si adattano alla mia natura interiore", "Cercare fonti esterne come guida o come auto apprezzamento"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno a capire chiaramente la forma e lo scopo della mia anima cosicché io possa scegliere forme di espressione che siano in armonia con la mia natura interiore." }, { nome: "Larch", tipo: "Fiore di Bach", squilibri: ["Dubitare delle mie capacità", "oO Depressione", "Pessimismo circa le mie capacità di avere successo"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno ad imparare da ogni esperienza ed agire con sicurezza usando la mia direzione interiore." }, { nome: "Queen of the Night", tipo: "Fiore del Deserto", squilibri: ["Essere vittima della fragilita della vita", "Stato di cecita e dissociazione causato dall'assorbimento di energie senza essere", "ancorato", "Impotenza ed inadeguatezza al cospetto di Dio", "Distorsione o blocco del principio ricettivo femminile"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno a sperimentare la padronanza dell'introspezione, del capire, del sentire e della sensualita." }, { nome: "Silver Princess", tipo: "Fiore Australiano", squilibri: ["Essere privo di scopo Q Abbattimento", "Piattezza emotiva", "Maneanza di direzione"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno a mettermi in sintonia con gli obiettivi della mia vita, agire con motivazione e direzione, ed esprimere completamente e liberamente il mie amore." }, { nome: "Slender Rice Flower", tipo: "Fiore Australiano", squilibri: ["Orgoglio O Gelosia", "Razzismo O Ristrettezza d'idee", "Fare dei paragoni tra me e gli altri"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno a cooperare con gli altri e riconoscere la yera umiltà come desiderio di vedere solo le cose migliori negli altri." }, { nome: "Pine", tipo: "Fiore di Bach", squilibri: ["Auto accusarmi per i miei errori", "I miei obblighi che mi opprimono", "Irrealistico senso di responsabilità", "Fatica e depressione"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno a prendermi quelle responsabilità che sono nel miglior interesse mio e degli altri. Valuterò i miei risultati e i miei fallimenti in maniera realistica e con amore." }, { nome: "Whitethorn", tipo: "Fiore del Deserto", squilibri: ["Disordine e confusione nelle situazioni", "Esagerare ed esaurirmi nel rendermi le cose difficili", "Tensione nervosa", "Soccombere a vecchi modelli, abitudini 0 situazioni che non sono pit: apropriate"], frasi: "Mi impegno con gentilezza, cortesia, amore e dandomi sostegno a vivere nel presente, sperimentare una pace interiore in modo che l'ottimismo e Ja dinamicita mi portino verso nuove direzioni." } ],
